<?php
namespace App\Domain\Hunts\Rewards\Claim;
use App\Domain\Hunts\Rewards\Claim\Data\HuntRewardClaimResult;use App\Domain\Hunts\Rewards\Claim\Exceptions\InsufficientInventoryCapacityForClaimException;use App\Domain\Hunts\Rewards\HuntRewardService;use App\Domain\Hunts\Rewards\HuntRewardStatus;use App\Domain\Inventory\Capacity\PendingRewardCapacityService;use App\Domain\Inventory\InventoryService;use App\Models\Character;use App\Models\CharacterItem;use App\Models\HuntReward;use App\Models\HuntRewardItem;use App\Models\Item;use Carbon\CarbonImmutable;use Illuminate\Support\Facades\DB;use InvalidArgumentException;use RuntimeException;
final class HuntRewardClaimService{private $inventory;private $capacity;private $rewards;public function __construct(InventoryService $inventory,PendingRewardCapacityService $capacity,HuntRewardService $rewards){$this->inventory=$inventory;$this->capacity=$capacity;$this->rewards=$rewards;}public function claimAllPendingForCharacter(Character $character){return DB::transaction(function()use($character){$now=CarbonImmutable::now();$lockedCharacter=Character::whereKey($character->id)->lockForUpdate()->firstOrFail();$inventory=CharacterItem::where('character_id',$lockedCharacter->id)->orderBy('id')->lockForUpdate()->get();$rewards=HuntReward::query()->select('hunt_rewards.*')->join('hunting_sessions','hunting_sessions.id','=','hunt_rewards.hunting_session_id')->where('hunting_sessions.character_id',$lockedCharacter->id)->where('hunt_rewards.status',HuntRewardStatus::PENDING)->orderBy('hunt_rewards.id')->lockForUpdate()->get();$rewardIds=$rewards->pluck('id');$lines=$rewardIds->isEmpty()?collect():HuntRewardItem::whereIn('hunt_reward_id',$rewardIds)->orderBy('id')->lockForUpdate()->get();list($quantities,$lineCount,$total)=$this->aggregate($lines);$itemIds=$inventory->pluck('item_id')->merge(array_keys($quantities))->unique()->sort()->values();$items=$itemIds->isEmpty()?collect():Item::whereIn('id',$itemIds)->orderBy('id')->lockForUpdate()->get()->keyBy('id');if($items->count()!==$itemIds->count())throw new RuntimeException('Inventory or reward references a missing Item.');foreach($items as $item)if((int)$item->max_stack<=0)throw new RuntimeException('Reward Item has invalid max_stack.');$capacity=$this->capacity->fromLoadedState($lockedCharacter,$inventory,$lines,$items,$now);if(!$capacity->claimFits())throw new InsufficientInventoryCapacityForClaimException($capacity);if(!empty($quantities))$this->inventory->addManyLocked($lockedCharacter,$items,$quantities,$inventory);foreach($rewards as $reward){if($reward->status!==HuntRewardStatus::PENDING)throw new RuntimeException('Invalid reward state transition.');$reward->status=HuntRewardStatus::CLAIMED;$reward->claimed_at=$now;$reward->save();}$updatedInventory=CharacterItem::where('character_id',$lockedCharacter->id)->orderBy('id')->get();$updatedCapacity=$this->capacity->fromLoadedState($lockedCharacter,$updatedInventory,collect(),$items,$now);$claimedItems=[];foreach($quantities as $itemId=>$quantity){$item=$items->get($itemId);$claimedItems[]=['item_id'=>(int)$itemId,'item_code'=>$item->code,'item_name'=>$item->name,'quantity'=>$quantity];}return new HuntRewardClaimResult(['claimed_rewards_count'=>$rewards->count(),'claimed_item_lines_count'=>$lineCount,'claimed_total_quantity'=>$total,'claimed_items'=>$claimedItems,'inventory_capacity'=>$updatedCapacity->toArray(),'pending_rewards_summary'=>$this->rewards->summaryPendingForCharacter($lockedCharacter)]);},3);}private function aggregate($lines){$quantities=[];$total=0;foreach($lines as $line){$quantity=$this->safePositive($line->quantity);$id=(int)$line->item_id;if($id<=0)throw new InvalidArgumentException('Invalid reward Item.');$old=isset($quantities[$id])?$quantities[$id]:0;if($quantity>PHP_INT_MAX-$old||$quantity>PHP_INT_MAX-$total)throw new InvalidArgumentException('Reward quantity overflow.');$quantities[$id]=$old+$quantity;$total+=$quantity;}ksort($quantities,SORT_NUMERIC);return[$quantities,$lines->count(),$total];}private function safePositive($value){if(is_int($value)&&$value>0)return$value;if(is_string($value)&&preg_match('/^[1-9][0-9]*$/',$value)&&strlen($value)<=strlen((string)PHP_INT_MAX)&&(strlen($value)<strlen((string)PHP_INT_MAX)||strcmp($value,(string)PHP_INT_MAX)<=0))return(int)$value;throw new InvalidArgumentException('Invalid reward quantity.');}}
